import{_ as e,c as s,o as n,a}from"./app.e1443878.js";const F=JSON.parse('{"title":"QueryFirst SelfTest()","description":"","frontmatter":{},"headers":[{"level":2,"title":"Why?","slug":"why","link":"#why","children":[]},{"level":2,"title":"How?","slug":"how","link":"#how","children":[]}],"relativePath":"selftest.md"}'),t={name:"selftest.md"},o=a(`<h1 id="queryfirst-selftest" tabindex="-1">QueryFirst SelfTest() <a class="header-anchor" href="#queryfirst-selftest" aria-hidden="true">#</a></h1><h2 id="why" tabindex="-1">Why? <a class="header-anchor" href="#why" aria-hidden="true">#</a></h2><p>As you deploy your code to different environments, keeping your database schemas synchronized with your evolving application code is a challenge. It frequently depends on developer rigour, and even automated solutions like Entity Framework migrations and Visual Studio database projects are not totally reliable. QueryFirst doesn&#39;t tell you how to do this, but it can help you ensure that it has been done correctly, and that the database on top of which you are deploying is compatible with the code being deployed.</p><h2 id="how" tabindex="-1">How? <a class="header-anchor" href="#how" aria-hidden="true">#</a></h2><p>QueryFirst does this by inserting a self-test method in the generated code. The test runs the query (in schema_only mode, just as we do at design time) against the environment&#39;s database (using QueryFirstConnectionFactory) and compares the resulting schema to the schema returned at design time. If the query doesn&#39;t run, or if there are breaking changes in the returned schema, the test will fail. (Additional columns at the end of a result set are not a breaking change.) As such, you can point the xunit command line runner at your application binary in its environment (config files resolved, database accessible) and, if everything passes, you have a strong guarantee that your database is available and correctly configured, your queries are all valid and their result sets are the expected ones.</p><p>This feature is turned off by default. To turn it on, add this to your config file...</p><div class="language-json"><button class="copy"></button><span class="lang">json</span><pre><code><span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">makeSelfTest</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: </span><span style="color:#89DDFF;">true</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"></span></code></pre></div><p>Then, you&#39;ll need to set up your project to host the generated methods. You&#39;re going to need five, yes five, nugets...</p><ul><li>Microsoft.NET.Test.Sdk</li><li>QueryFirst.CoreLib</li><li>xunit</li><li>Xunit.DependencyInjection</li><li>xunit.runner.visualstudio</li></ul><p>If you haven&#39;t already got one, you&#39;re going to need a Startup class to register your production data source for DI. In the example below, NorthwindDB is our concrete implementation of QueryFirst.QueryFirstConnectionFactory.</p><div class="language-C#"><button class="copy"></button><span class="lang">C#</span><pre><code><span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">class</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Startup</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">void</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">ConfigureServices</span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">IServiceCollection</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">services</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">        services</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">AddTransient</span><span style="color:#89DDFF;">&lt;</span><span style="color:#FFCB6B;">QueryFirst</span><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">QueryFirstConnectionFactory</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">NorthwindDB</span><span style="color:#89DDFF;">&gt;();</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div>`,11),l=[o];function r(i,p,c,d,y,u){return n(),s("div",null,l)}const D=e(t,[["render",r]]);export{F as __pageData,D as default};
